module top_module(
	intrIn, intr,
	ack, clk, rst
);input intrIn;
	output intr;
	input ack;
	input clk, rst;

	reg obf_intr_r;

	always @(posedge clk) begin
		if (rst) begin
			obf_intr_r <= 1'b0;
		end
		else if (ack) begin
			obf_intr_r <= 1'b0;
		end
		else begin
			obf_intr_r <= obf_intr_r | intrIn;
		end
	end 

	assign intr = obf_intr_r;endmodule
